class Solution {
public:
    vector<string> removeSubfolders(vector<string>& folder) {
        sort(folder.begin(), folder.end());
        vector<string> res;
        for (const string& f : folder) {
            bool isSub = false;
            for (const string& p : res) {
                if (f.size() > p.size() && f[p.size()] == '/' && f.substr(0, p.size()) == p) {
                    isSub = true;
                    break;
                }
            }
            if (!isSub) res.push_back(f);
        }
        return res;
    }
};
